import * as t from "io-ts";
import { BaseIntent } from "./baseIntent";
import { intentTypes } from "./intentType";
import { optionalBoolean, optionalString } from "../../../utils";
import { TokenRecipientEntry } from "./tokenRecipientEntry";
import { EthBuildOptions } from "./ethBuildOptions";

export const ConsolidateTokenIntent = t.intersection([
  BaseIntent,
  EthBuildOptions,
  t.type({
    intentType: intentTypes.consolidateToken,
    recipients: t.array(TokenRecipientEntry),
  }),
  t.partial({
    consolidateId: optionalString,
    keepAlive: optionalBoolean,
  }),
]);

export type ConsolidateTokenIntent = t.TypeOf<typeof ConsolidateTokenIntent>;
